#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

#define CONV_INT(i) ((class_T)(i))
#define MAD(a, b, c) ((a) * (b) + (c))

#ifdef ENABLE_HP
#define EQUAL(a, b) all((a) == (b))
#else
#define EQUAL(a, b) ((a) == (b))
#endif

__kernel void benchmark_func(const class_T seed, __global class_T *g_data) {
    const int blockSize = (int)blockdim;

#ifdef BLOCK_STRIDED
    const int stride = blockSize;
    const int idx = (int)get_group_id(0) * blockSize * (int)ELEMENTS_PER_THREAD +
                    (int)get_local_id(0);
    const int big_stride =
        (int)get_num_groups(0) * blockSize * (int)ELEMENTS_PER_THREAD;
#else
    const int stride = (int)get_global_size(0);
    const int idx = (int)get_global_id(0);
    const int big_stride = (int)get_global_size(0) * (int)ELEMENTS_PER_THREAD;
#endif

    class_T tmps[ELEMENTS_PER_THREAD];

    for (int k = 0; k < (int)FUSION_DEGREE; k++) {
        for (int j = 0; j < (int)ELEMENTS_PER_THREAD; j++) {
            tmps[j] = g_data[idx + j * stride + k * big_stride];

            for (int i = 0; i < (int)COMPUTE_ITERATIONS; i++) {
                tmps[j] = MAD(tmps[j], tmps[j], seed);
            }
        }

        class_T sum = CONV_INT(0);
        for (int j = 0; j < (int)ELEMENTS_PER_THREAD; j += 2) {
            class_T b = (j + 1 < (int)ELEMENTS_PER_THREAD) ? tmps[j + 1] : CONV_INT(0);
            sum = MAD(tmps[j], b, sum);
        }

        if (EQUAL(sum, CONV_INT(-1))) {
            g_data[idx + k * big_stride] = sum;
        }
    }
}
